// PACファイル設定例
function FindProxyForURL(url, host) {
  // ループバック・内部IPはバイパス
  if (isPlainHostName(host) || isInNet(host, "10.0.0.0", "255.0.0.0") ||
      isInNet(host, "192.168.0.0", "255.255.0.0")) {
    return "DIRECT";
  }
  // ZPAアプリはバイパス（ZCCが処理）
  if (dnsDomainIs(host, ".internal.example.com")) {
    return "DIRECT";
  }
  // それ以外はZscalerプロキシへ
  return "PROXY proxy.zscalertwo.net:80; PROXY proxy2.zscalertwo.net:80; DIRECT";
}
